args.newString:
    _generateId() {
      return Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 7);
    }
  };

  // ==============================
  // 视图层 - TodoRenderer
  // ==============================

  const TodoRenderer = {
    /**
     * 根据应用状态渲染整个待办列表
     * @param {object} appState - 应用状态快照 { todos: [] }
     */
    render(appState) {
      var todoList = document.getElementById('todo-list');
      var emptyState = document.getElementById('empty-state');

      // 先清空列表容器
      while (todoList.firstChild) {
        todoList.removeChild(todoList.firstChild);
      }

      if (appState.todos.length === 0) {
        // 列表为空时显示空状态提示，隐藏列表
        emptyState.style.display = '';
        todoList.style.display = 'none';
        return;
      }

      // 有数据时隐藏空状态提示，显示列表
      emptyState.style.display = 'none';
      todoList.style.display = '';

      // 为每条待办事项生成 DOM 节点
      appState.todos.forEach(function(todo) {
        var li = document.createElement('li');
        li.setAttribute('data-id', todo.id);

        if (todo.completed) {
          li.classList.add('completed');
        }

        // 复选框
        var checkbox = document.createElement('input');
        checkbox.type = 'checkbox';
        checkbox.checked = todo.completed;
        checkbox.setAttribute('data-id', todo.id);
        checkbox.className = 'toggle-checkbox';

        // 待办文本（使用 textContent 防止 XSS）
        var span = document.createElement('span');
        span.textContent = todo.text;

        // 删除按钮
        var deleteBtn = document.createElement('button');
        deleteBtn.textContent = '删除';
        deleteBtn.className = 'delete-btn';
        deleteBtn.setAttribute('data-id', todo.id);

        li.appendChild(checkbox);
        li.appendChild(span);
        li.appendChild(deleteBtn);

        todoList.appendChild(li);
      });
    },

    /**
     * 清空输入框并将焦点定位到输入框
     */
    clearAndFocusInput() {
      var input = document.getElementById('todo-input');
      input.value = '';
      input.focus();
    },

    /**
     * 为输入框添加抖动动画效果
     * 动画结束后自动移除 .shake 类
     */
    shakeInput() {
      var input = document.getElementById('todo-input');
      input.classList.add('shake');
      input.addEventListener('animationend', function handler() {
        input.classList.remove('shake');
        input.removeEventListener('animationend', handler);
      });
    }
  };

  // ==============================
  // 应用控制层 - TodoApp
  // ==============================

  const TodoApp = {
    /**
     * 初始化应用：加载数据 → 渲染视图 → 绑定事件
     */
    init() {
      // 从 TodoStore 加载数据
      var initialState = TodoStore.load();

      // 渲染初始视图
      TodoRenderer.render(initialState);

      // 绑定事件监听器
      this._bindEvents();
    },

    /**
     * 绑定所有事件监听器
     */
    _bindEvents() {
      var self = this;
      var input = document.getElementById('todo-input');
      var addBtn = document.getElementById('add-btn');
      var todoList = document.getElementById('todo-list');

      // 输入框 keydown 事件：Enter 键触发添加
      input.addEventListener('keydown', function(e) {
        if (e.key === 'Enter') {
          self.handleAddTodo();
        }
      });

      // 添加按钮 click 事件
      addBtn.addEventListener('click', function() {
        self.handleAddTodo();
      });

      // 列表区域事件委托：在 #todo-list 上监听
      todoList.addEventListener('change', function(e) {
        if (e.target.classList.contains('toggle-checkbox')) {
          var id = e.target.getAttribute('data-id');
          self.handleToggleTodo(id);
        }
      });

      todoList.addEventListener('click', function(e) {
        if (e.target.classList.contains('delete-btn')) {
          var id = e.target.getAttribute('data-id');
          self.handleDeleteTodo(id);
        }
      });
    },

    /**
     * 处理添加待办事项
     */
    handleAddTodo() {
      var input = document.getElementById('todo-input');
      var text = input.value.trim();

      // 非空验证
      if (text === '') {
        TodoRenderer.shakeInput();
        return;
      }

      // 调用数据层添加 → 渲染视图 → 清空输入框
      var newState = TodoStore.addTodo(text);
      TodoRenderer.render(newState);
      TodoRenderer.clearAndFocusInput();
    },

    /**
     * 处理切换待办事项完成状态
     * @param {string} id - 待办事项 ID
     */
    handleToggleTodo(id) {
      var newState = TodoStore.toggleTodo(id);
      TodoRenderer.render(newState);
    },

    /**
     * 处理删除待办事项
     * @param {string} id - 待办事项 ID
     */
    handleDeleteTodo(id) {
      var newState = TodoStore.deleteTodo(id);
      TodoRenderer.render(newState);
    }
  };

  // DOM 就绪后初始化应用
  document.addEventListener('DOMContentLoaded', function() {
    TodoApp.init();
  });
</script>

