// ====== 完整模拟：包含 DOM 模拟的事件委托测试 ======

// 模拟 DOM 元素
function createMockElement(tag, id) {
  var children = [];
  var attributes = {};
  var styles = {};
  var eventListeners = {};

  var elem = {
    tagName: tag.toUpperCase(),
    id: id || '',
    className: '',
    childNodes: children,
    children: children,
    style: styles,
    type: '',
    checked: false,
    textContent: '',
    value: '',
    parentNode: null,

    classList: {
      _classes: [],
      add: function(cls) { if (this._classes.indexOf(cls) === -1) this._classes.push(cls); },
      remove: function(cls) { this._classes = this._classes.filter(function(c) { return c !== cls; }); },
      contains: function(cls) { return this._classes.indexOf(cls) >= 0; }
    },

    setAttribute: function(name, value) { attributes[name] = String(value); },
    getAttribute: function(name) { return attributes[name] || null; },

    appendChild: function(child) { 
      children.push(child); 
      child.parentNode = this;
      return child;
    },
    removeChild: function(child) {
      var idx = children.indexOf(child);
      if (idx >= 0) children.splice(idx, 1);
      return child;
    },

    addEventListener: function(event, handler) {
      if (!eventListeners[event]) eventListeners[event] = [];
      eventListeners[event].push(handler);
    },

    // 模拟事件触发（含冒泡）
    dispatchEvent: function(event) {
      var target = event.target;
      // 构建冒泡链
      var chain = [];
      var current = target;
      while (current) {
        chain.push(current);
        current = current.parentNode;
      }

      for (var i = 0; i < chain.length; i++) {
        var el = chain[i];
        var listeners = eventListeners[event.type] || [];
        for (var j = 0; j < listeners.length; j++) {
          listeners[j](event);
        }
      }
    }
  };

  return elem;
}

// 模拟 document
var elements = {};
var document = {
  getElementById: function(id) { return elements[id] || null; },
  createElement: function(tag) { return createMockElement(tag); }
};

// 注册 DOM 元素
var todoListEl = createMockElement('ul', 'todo-list');
var emptyStateEl = createMockElement('div', 'empty-state');
var inputEl = createMockElement('input', 'todo-input');
var addBtnEl = createMockElement('button', 'add-btn');
elements['todo-list'] = todoListEl;
elements['empty-state'] = emptyStateEl;
elements['todo-input'] = inputEl;
elements['add-btn'] = addBtnEl;

// ====== 实际应用代码（从 index.html 提取） ======
var STORAGE_KEY = 'todo-app-data';
var _storageAvailable = false;
var state = { todos: [] };

var TodoStore = {
  load: function() {
    state = { todos: [] };
    return this.getState();
  },
  addTodo: function(text) {
    var trimmedText = text.trim();
    var newTodo = {
      id: this._generateId(),
      text: trimmedText,
      completed: false,
      createdAt: Date.now()
    };
    state.todos.push(newTodo);
    this._save();
    return this.getState();
  },
  toggleTodo: function(id) {
    var todo = state.todos.find(function(item) {
      return item.id === id;
    });
    if (todo) {
      todo.completed = !todo.completed;
      this._save();
    }
    return this.getState();
  },
  deleteTodo: function(id) {
    state.todos = state.todos.filter(function(item) {
      return item.id !== id;
    });
    this._save();
    return this.getState();
  },
  getState: function() {
    return JSON.parse(JSON.stringify(state));
  },
  _save: function() {
    if (!_storageAvailable) return;
  },
  _generateId: function() {
    return Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 7);
  }
};

var TodoRenderer = {
  render: function(appState) {
    var todoList = document.getElementById('todo-list');
    var emptyState = document.getElementById('empty-state');

    // 清空
    while (todoList.children.length > 0) {
      todoList.removeChild(todoList.children[0]);
    }

    if (appState.todos.length === 0) {
      emptyState.style.display = '';
      todoList.style.display = 'none';
      return;
    }

    emptyState.style.display = 'none';
    todoList.style.display = '';

    appState.todos.forEach(function(todo) {
      var li = createMockElement('li');
      li.setAttribute('data-id', todo.id);

      if (todo.completed) {
        li.classList.add('completed');
      }

      var checkbox = createMockElement('input');
      checkbox.type = 'checkbox';
      checkbox.checked = todo.completed;
      checkbox.setAttribute('data-id', todo.id);
      checkbox.className = 'toggle-checkbox';
      checkbox.classList._classes = ['toggle-checkbox'];

      var span = createMockElement('span');
      span.textContent = todo.text;

      var deleteBtn = createMockElement('button');
      deleteBtn.textContent = '删除';
      deleteBtn.className = 'delete-btn';
      deleteBtn.setAttribute('data-id', todo.id);
      deleteBtn.classList._classes = ['delete-btn'];

      li.appendChild(checkbox);
      li.appendChild(span);
      li.appendChild(deleteBtn);
      todoList.appendChild(li);
    });
  }
};

var TodoApp = {
  init: function() {
    var initialState = TodoStore.load();
    TodoRenderer.render(initialState);
    this._bindEvents();
  },
  _bindEvents: function() {
    var self = this;
    var todoList = document.getElementById('todo-list');

    todoList.addEventListener('change', function(e) {
      console.log('[change event] target className:', e.target.className);
      if (e.target.classList.contains('toggle-checkbox')) {
        var id = e.target.getAttribute('data-id');
        console.log('[change] Matched toggle-checkbox, id:', id);
        self.handleToggleTodo(id);
      } else {
        console.log('[change] NOT matched toggle-checkbox!');
      }
    });
  },
  handleToggleTodo: function(id) {
    console.log('[handleToggleTodo] id:', id);
    var newState = TodoStore.toggleTodo(id);
    console.log('[handleToggleTodo] after toggle completed:', newState.todos[0].completed);
    TodoRenderer.render(newState);
  }
};

// ====== 运行完整测试 ======
