// ====== 使用 Puppeteer 在真实 Chromium 中测试 ======
const puppeteer = require('puppeteer');
const path = require('path');
const fs = require('fs');

(async () => {
  const browser = await puppeteer.launch({
    headless: 'new',
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const page = await browser.newPage();

  // 监听控制台输出
  page.on('console', msg => {
    console.log('[Browser]', msg.text());
  });

  // 监听页面错误
  page.on('pageerror', error => {
    console.log('[Page Error]', error.message);
  });

  // 加载 index.html
  const filePath = 'file:///' + path.resolve(__dirname, 'index.html').replace(/\\/g, '/');
  console.log('Loading:', filePath);
  await page.goto(filePath);

  // 等待页面加载
  await page.waitForFunction(() => {
    return document.readyState === 'complete';
  });

  console.log('\n=== 页面加载完成 ===');

  // 检查初始状态
  const initialState = await page.evaluate(() => {
    const todoList = document.getElementById('todo-list');
    return {
      listChildren: todoList.children.length,
      listDisplay: todoList.style.display,
      emptyStateDisplay: document.getElementById('empty-state').style.display
    };
  });
  console.log('初始状态:', JSON.stringify(initialState));

  // 添加待办事项
  console.log('\n=== 添加待办事项 ===');
  await page.evaluate(() => {
    const input = document.getElementById('todo-input');
    input.value = '测试待办事项';
    const addBtn = document.getElementById('add-btn');
    addBtn.click();
  });

  // 等待渲染
  await page.waitForTimeout(100);

  // 检查添加后的状态
  const afterAdd = await page.evaluate(() => {
    const todoList = document.getElementById('todo-list');
    const li = todoList.children[0];
    const checkbox = li.querySelector('input[type="checkbox"]');
    const span = li.querySelector('span');
    return {
      listChildren: todoList.children.length,
      liDataId: li.getAttribute('data-id'),
      checkboxClassName: checkbox.className,
      checkboxDataId: checkbox.getAttribute('data-id'),
      checkboxType: checkbox.type,
      checkboxChecked: checkbox.checked,
      spanText: span.textContent,
      liHasCompleted: li.classList.contains('completed')
    };
  });
  console.log('添加后状态:', JSON.stringify(afterAdd, null, 2));

  // ====== 测试 1: 模拟点击复选框 ======
  console.log('\n=== 测试 1: 使用 Puppeteer 点击复选框 ===');

  const checkbox = await page.$('#todo-list input[type="checkbox"]');
  console.log('找到 checkbox:', !!checkbox);

  // 点击复选框
  await checkbox.click();

  // 等待渲染
  await page.waitForTimeout(200);

  // 检查点击后的状态
  const afterClick = await page.evaluate(() => {
    const todoList = document.getElementById('todo-list');
    if (todoList.children.length === 0) return { error: 'No children' };
    const li = todoList.children[0];
    const cb = li.querySelector('input[type="checkbox"]');
    const span = li.querySelector('span');
    return {
      checkboxChecked: cb.checked,
      liHasCompleted: li.classList.contains('completed'),
      spanText: span.textContent,
      // 获取计算样式
      spanTextDecoration: window.getComputedStyle(span).textDecoration,
      spanColor: window.getComputedStyle(span).color
    };
  });
  console.log('点击后状态:', JSON.stringify(afterClick, null, 2));

  // ====== 测试 2: 检查 TodoStore 内部状态 ======
  console.log('\n=== 测试 2: 检查 TodoStore 状态 ===');

  // 注意：const 变量不在 window 上，需要通过页面内脚本访问
  const storeState = await page.evaluate(() => {
    // 尝试通过 window 访问（const 不在 window 上）
    // 需要另一种方式访问
    try {
      // 通过读取 localStorage 来获取状态
      const raw = localStorage.getItem('todo-app-data');
      return JSON.parse(raw);
    } catch(e) {
      return { error: e.message };
    }
  });
  console.log('localStorage 状态:', JSON.stringify(storeState, null, 2));

  // ====== 测试 3: 直接在页面内执行 toggleTodo ======
  console.log('\n=== 测试 3: 在页面内直接调用逻辑 ===');

  const directToggleResult = await page.evaluate(() => {
    // 通过在页面上下文中执行脚本来访问 const 变量
    // 我们需要用另一种方式 - 通过脚本注入
    const script = document.createElement('script');
    script.textContent = `
      window.__toggleResult = {};
      try {
        // 直接操作 localStorage 数据来验证
        var raw = localStorage.getItem('todo-app-data');
        var data = JSON.parse(raw);
        if (data.todos.length > 0) {
          window.__toggleResult.beforeCompleted = data.todos[0].completed;
        }
      } catch(e) {
        window.__toggleResult.error = e.message;
      }
    `;
    document.head.appendChild(script);
    document.head.removeChild(script);
    return window.__toggleResult;
  });
  console.log('直接访问结果:', JSON.stringify(directToggleResult));

  // ====== 测试 4: 注入完整测试脚本 ======
  console.log('\n=== 测试 4: 注入测试脚本到页面 ===');

  const injectResult = await page.evaluate(() => {
    return new Promise((resolve) => {
      const script = document.createElement('script');
      script.textContent = `
        (function() {
          var result = {};
          try {
