            // 尝试通过 DOM 事件直接测试
            // 先获取当前 ID
            var currentId = cb.getAttribute('data-id');
            result.currentId = currentId;

            // 手动模拟一次完整的 change 事件流程
            result.beforeClick = cb.checked;

